const r=".toast{height:100%;max-width:400px;display:grid;gap:10px;grid-template-columns:1em auto 1em;border-radius:5px;padding:5px 12px;box-sizing:border-box;font-size:var(--font-d2);background-color:var(--green-50);border:1px solid color-mix(in lab,var(--green-50) 100%,var(--gray-500) 20%);color:var(--green-800);box-shadow:0 1px 2px #0000000d,0 0 5px #0000000d;animation:toastPop .1s ease-in-out forwards}.toast[toast-type=warning]{background-color:var(--orange-50);border:1px solid color-mix(in lab,var(--orange-50) 100%,var(--gray-500) 20%);color:var(--orange-800)}.toast[toast-type=error]{background-color:var(--red-50);border:1px solid color-mix(in lab,var(--red-50) 100%,var(--gray-500) 20%);color:var(--red-800)}.toast[is-hidden]{display:none}@keyframes toastPop{0%{transform:scale(.8);opacity:0}90%{transform:scale(1.1);opacity:.9}to{transform:scale(1);opacity:1}}.svg-icon{display:flex;justify-content:center;align-items:center;width:1em;height:1em;color:currentColor;transition:transform 80ms linear;transform-origin:center;position:relative;top:3px}.svg-icon svg{fill:currentColor;width:100%;height:100%}.cross-icon{color:var(--gray-800);width:10px;height:10px;top:5px;cursor:pointer}.cross-icon:hover{color:var(--gray-600)}.cross-icon:active{color:var(--gray-700)}.message{min-width:0px;line-height:1.2;white-space:pre-wrap;word-break:break-word}";export{r as c};